  1→import { RichTextPlugin } from "@lexical/react/LexicalRichTextPlugin";
  2→import { ContentEditable } from "@lexical/react/LexicalContentEditable";
  3→import ImageNode from "../Editor/nodes/ImageNode";
  4→import { HeadingNode, QuoteNode } from "@lexical/rich-text";
  5→import { LexicalComposer } from "@lexical/react/LexicalComposer";
  6→import { LexicalErrorBoundary } from "@lexical/react/LexicalErrorBoundary";
  7→import { useLocation, useNavigate, useParams } from "react-router-dom";
  8→import './contentviewer.css'
  9→import { useEffect, useMemo, useRef, useState } from "react";
 10→import { AnimatePresence, motion } from "framer-motion";
 11→import { MoonLoader } from "react-spinners";
 12→import CalculateText from "../postCards/calculateReadingTime";
 13→import ParseContent from "../postCards/parseData";
 14→import { useBookMarkMutation, useFollowMutation, useLikeMutation } from "../../../utils/useMutation";
 15→import { useAuth } from "../../../Context/useAuth";
 16→import CommentSection from "../../comments/comments";
 17→import CanvasViewer from "../Canvas/CanvasViewer";
 18→import debounce from "../../../../helpers/debounce";
 19→import formatCounts from "../../../../helpers/fomatCounts";
 20→import { handleClickProfile, handleCLickContent } from "../../../../helpers/handleClicks";
 21→import { getFollowsData, getJournalById } from "../../../../API/Api";
 22→import { useQuery } from "@tanstack/react-query";
 23→import VerifiedBadge from "../../Badge/VerifiedBadge";
 24→import { getCanvasWholeText, parseCanvasDoc } from "../../../utils/canvasDoc";
 25→import RepostModal from "../../RepostModal/RepostModal";
 26→
 27→const normalizeInteractionFlag = (value) => {
 28→    if(typeof value === 'boolean') return value;
 29→    if(typeof value === 'string'){
 30→        const normalized = value.trim().toLowerCase();
 31→        if(normalized === 'true') return true;
 32→        if(normalized === 'false') return false;
 33→    }
 34→    if(typeof value === 'number'){
 35→        return value === 1;
 36→    }
 37→    return Boolean(value);
 38→};
 39→
 40→const normalizeCount = (value) => {
 41→    const number = Number(value);
 42→    if(!Number.isFinite(number) || number < 0){
 43→        return 0;
 44→    }
 45→    return number;
 46→};
 47→
 48→const getNextToggleCount = (isActive, currentCount) => {
 49→    return isActive
 50→        ? Math.max(0, currentCount - 1)
 51→        : currentCount + 1;
 52→};
 53→
 54→const ContentView = () => {
 55→    const navigate = useNavigate();
 56→    const [showBackButton, setShowBackButton] = useState(true);
 57→    const { session, user, openAuthModal } = useAuth();
 58→
 59→    const timeOutRef = useRef();
 60→    const timeOutRefBookmark = useRef();
 61→    const likeInFlightRef = useRef(false);
 62→    const bookmarkInFlightRef = useRef(false);
 63→
 64→    const [showCommentsContainer, setShowCommentsContainer] = useState(false);
 65→    const [isLiked, setIsliked] = useState(false);
 66→    const [likesCount, setLikesCount] = useState(0);
 67→    const [isBookmarked, setIsBookmarked] = useState(false);
 68→    const [bookmarkCounts, setBookmarkCounts] = useState(0);
 69→
 70→    const [bookmarkedMessage, setBookmarkedMessage] = useState('');
 71→    const [showRepostModal, setShowRepostModal] = useState(false);
 72→
 73→    const contentRef = useRef();
 74→
 75→    const theme = {
 76→        paragraph: 'editor-paragraph',
 77→        heading: {
 78→            h1: 'editor-heading-h1',
 79→            h2: 'editor-heading-h2',
 80→            h3: 'editor-heading-h3',
 81→        },
 82→        quote: 'editor-quote',
 83→        text: {
 84→            bold: 'editor-text-bold',
 85→            italic: 'editor-text-italic',
 86→            underline: 'editor-text-underline',
 87→        }
 88→    }
 89→
 90→    const location = useLocation();
 91→    const { journalId } = useParams();
 92→    const statePostData = location.state;
 93→    const shouldFetchPost = !!journalId && (!statePostData || !statePostData?.postType);
 94→
 95→    const { data: fetchedJournalData, isLoading: isLoadingJournalById } = useQuery({
 96→        queryKey: ['journalById', journalId, user?.userData?.[0]?.id],
 97→        queryFn: ({ queryKey }) => getJournalById(queryKey[1], queryKey[2]),
 98→        enabled: shouldFetchPost,
 99→        staleTime: 1000 * 60 * 5,
100→        refetchOnWindowFocus: false,
101→    });
102→
103→    const postData = useMemo(() => {
104→        const journal = fetchedJournalData?.journal;
105→        if(journal){
106→            const postType = journal?.post_type || 'text';
107→            const parsedContent = ParseContent(journal?.content);
108→            const canvasDoc = postType === 'canvas' ? parseCanvasDoc(journal?.canvas_doc) : null;
109→            const wholeText = postType === 'canvas'
110→                ? getCanvasWholeText(canvasDoc)
111→                : (parsedContent?.wholeText || '');
112→
113→            return {
114→                postType: postType,
115→                content: journal?.content,
116→                canvasDoc: canvasDoc,
117→                wholeText: wholeText,
118→                title: journal?.title,
119→                userId: journal?.users?.id || journal?.user_id,
120→                name: journal?.users?.name,
121→                avatar: journal?.users?.image_url,
122→                created_at: journal?.created_at,
123→                journalId: journal?.id,
124→                isLiked: journal?.has_liked,
125→                commentsCount: journal?.comment_count?.[0]?.count || 0,
126→                isBookmarked: journal?.has_bookmarked,
127→                likesCount: journal?.like_count?.[0]?.count || 0,
128→                bookmarksCount: journal?.bookmark_count?.[0]?.count || 0,
129→                badge: journal?.users?.badge,
130→                isRepost: journal?.is_repost === true,
131→                repostCaption: journal?.repost_caption || '',
132→                repostSource: journal?.repost_source || null
133→            };
134→        }
135→
136→        if(!statePostData){
137→            return null;
138→        }
139→
140→        const inferredPostType = statePostData?.postType || (statePostData?.canvasDoc ? 'canvas' : 'text');
141→        const parsedContent = ParseContent(statePostData?.content);
142→        const canvasDoc = inferredPostType === 'canvas' ? parseCanvasDoc(statePostData?.canvasDoc) : null;
143→
144→        return {
145→            postType: inferredPostType,
146→            content: statePostData?.content,
147→            canvasDoc: canvasDoc,
148→            wholeText: inferredPostType === 'canvas'
149→                ? (statePostData?.wholeText || getCanvasWholeText(canvasDoc))
150→                : (statePostData?.wholeText || parsedContent?.wholeText || ''),
151→            title: statePostData?.title,
152→            userId: statePostData?.userId,
153→            name: statePostData?.name,
154→            avatar: statePostData?.avatar,
155→            created_at: statePostData?.created_at,
156→            journalId: statePostData?.journalId,
157→            isLiked: statePostData?.isLiked,
158→            commentsCount: statePostData?.commentsCount || 0,
159→            isBookmarked: statePostData?.isBookmarked,
160→            likesCount: statePostData?.likesCount || 0,
161→            bookmarksCount: statePostData?.bookmarksCount || 0,
162→            badge: statePostData?.badge,
163→            isRepost: statePostData?.isRepost === true,
164→            repostCaption: statePostData?.repostCaption || '',
165→            repostSource: statePostData?.repostSource || null
166→        };
167→    }, [fetchedJournalData, statePostData]);
168→
169→    const { data: followsData, isLoading: isLoadingFollows } = useQuery({
170→        queryKey: ['followsData', user?.userData?.[0]?.id, postData?.userId],
171→        queryFn: ({ queryKey }) => getFollowsData(queryKey[1], queryKey[2]),
172→        staleTime: 1000 * 60 * 60,
173→        cacheTime: 1000 * 60 * 60,
174→        enabled: !!user?.userData?.[0]?.id && !!postData?.userId,
175→    });
176→
177→    const handleclickUserProfile = handleClickProfile(navigate);
178→    const viewContent = handleCLickContent(navigate);
179→
180→    const mutationLike = useLikeMutation(session, user?.userData?.[0]?.id);
181→    const handleClickLike = async (e, journalId, receiverId, senderImageUrl, sendername, senderEmail) => {
182→        e.stopPropagation();
183→        if(likeInFlightRef.current){
184→            return;
185→        }
186→        if(!session){
187→            openAuthModal?.();
188→            return;
189→        }
190→        const wasLiked = normalizeInteractionFlag(isLiked);
191→        likeInFlightRef.current = true;
192→        setIsliked(!wasLiked);
193→        setLikesCount((prevCount) => getNextToggleCount(wasLiked, normalizeCount(prevCount)));
194→        mutationLike.mutate(
195→            { journalId, receiverId, senderImageUrl, sendername, senderEmail },
196→            {
197→                onSettled: () => {
198→                    likeInFlightRef.current = false;
199→                }
200→            }
201→        );
202→    }
203→
204→    const mutationBookmark = useBookMarkMutation(session, user?.userData?.[0]?.id);
205→    const handleClickBookmark = async (e, journalId) => {
206→        e.stopPropagation();
207→        if(bookmarkInFlightRef.current){
208→            return;
209→        }
210→        if(!session){
211→            openAuthModal?.();
212→            return;
213→        }
214→        const wasBookmarked = normalizeInteractionFlag(isBookmarked);
215→        bookmarkInFlightRef.current = true;
216→        setIsBookmarked(!wasBookmarked);
217→        setBookmarkCounts((prevCount) => getNextToggleCount(wasBookmarked, normalizeCount(prevCount)));
218→        let response = null;
219→        try {
220→            response = await mutationBookmark.mutateAsync({ journalId });
221→        } finally {
222→            bookmarkInFlightRef.current = false;
223→        }
224→        
225→        if(timeOutRefBookmark.current){
226→            clearTimeout(timeOutRefBookmark.current);
227→        }
228→        if (response?.message === 'success') {
229→            setBookmarkedMessage('Post was added to your Bookmarks'); 
230→        } else if(response?.message === 'deleted'){
231→            setBookmarkedMessage('Post was removed from your Bookmarks');
232→        }
233→            
234→        timeOutRefBookmark.current = setTimeout(() => {
235→            setBookmarkedMessage('');
236→        }, 1500);
237→
238→    }
239→    const debounceClickBookmark = debounce(handleClickBookmark, 100);
240→
241→    const mutationFollow = useFollowMutation(session);
242→    const handleClickFollow = async (e, followingId, followerId) => {
243→        e.stopPropagation();
244→        mutationFollow.mutate({ followingId, followerId });
245→    }
246→    const debounceClickFollow = debounce(handleClickFollow, 100);
247→
248→    const handleBackLocation = (e) => {
249→        e.stopPropagation();
250→        window.history.back();
251→    }
252→
253→    const hanldeClickComments = (e) => {
254→        e.stopPropagation();
255→        setShowCommentsContainer(true);
256→    }
257→
258→    const handleRemixCanvas = (e) => {
259→        e.stopPropagation();
260→        if(!session){
261→            return;
262→        }
263→
264→        const sourceTitle = typeof postData?.title === 'string' ? postData.title.trim() : '';
265→        const remixTitle = sourceTitle.toLowerCase().startsWith('remix:')
266→            ? sourceTitle
267→            : `Remix: ${sourceTitle || 'Canvas'}`;
268→
269→        navigate('/home', {
270→            state: {
271→                openEditor: true,
272→                editorMode: 'canvas',
273→                initialTitle: remixTitle,
274→                initialCanvasDoc: postData?.canvasDoc || null,
275→                remixSource: {
276→                    journalId: postData?.journalId,
277→                    authorName: postData?.name || 'Unknown'
278→                }
279→            }
280→        });
281→    }
282→
283→    const handleCLoseComments = () => {
284→        setShowCommentsContainer(false);
285→    }
286→
287→    useEffect(() => {
288→        if (!postData) return;
289→        setLikesCount(normalizeCount(postData?.likesCount));
290→        setBookmarkCounts(normalizeCount(postData?.bookmarksCount));
291→        setIsliked(normalizeInteractionFlag(postData?.isLiked));
292→        setIsBookmarked(normalizeInteractionFlag(postData?.isBookmarked));
293→    }, [postData?.likesCount, postData?.bookmarksCount, postData?.isLiked, postData?.isBookmarked]);
294→
295→    useEffect(() => {
296→        if (postData?.title) {
297→            document.title = `${postData.title} | Iskrib`;
298→            return () => {
299→                document.title = 'Iskrib';
300→            };
301→        }
302→
303→        document.title = 'Iskrib';
304→    }, [postData?.title]);
305→
306→    useEffect(() => {
307→        const hideBackBttn = () => {
308→            setShowBackButton(false);
309→            if (timeOutRef.current) {
310→                clearTimeout(timeOutRef.current);
311→            }
312→            timeOutRef.current = setTimeout(() => {
313→                setShowBackButton(true);
314→            }, 300);
315→        }
316→
317→        document.addEventListener('scroll', hideBackBttn, true);
318→        return () => {
319→            if (timeOutRef.current) {
320→                clearTimeout(timeOutRef.current);
321→            }
322→            document.removeEventListener('scroll', hideBackBttn, true);
323→        }
324→    }, []);
325→
326→    if (isLoadingJournalById || isLoadingFollows) {
327→        return (
328→            <div className="cv-loading">
329→                <MoonLoader loading={isLoadingJournalById || isLoadingFollows} color="var(--loader-color)" size={25} />
330→            </div>
331→        )
332→    }
333→
334→    if (!postData) {
335→        return (
336→            <div className="cv-loading">
337→                <p>Post is unavailable.</p>
338→                <button onClick={handleBackLocation} className="cv-back-btn" style={{ marginTop: "12px" }}>
339→                    Go back
340→                </button>
341→            </div>
342→        )
343→    }
344→
345→    return (
346→        <>
347→            {showCommentsContainer && (
348→                <AnimatePresence>
349→                    <CommentSection onclose={handleCLoseComments} postId={postData?.journalId} receiverId={postData?.userId} />
350→                </AnimatePresence>
351→            )}
352→
353→            <div ref={contentRef} className="cv-container">
354→                {/* Back header */}
355→                <AnimatePresence>
356→                    {showBackButton && (
357→                        <motion.div
358→                            className="cv-header"
359→                            initial={{ opacity: 0 }}
360→                            animate={{ opacity: 1, transition: { duration: 0.15 } }}
361→                            exit={{ opacity: 0, transition: { duration: 0.15 } }}
362→                        >
363→                            <button onClick={handleBackLocation} className="cv-back-btn">
364→                                <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 -960 960 960">
365→                                    <path d="M360-240 120-480l240-240 56 56-144 144h568v80H272l144 144-56 56Z" />
366→                                </svg>
367→                            </button>
368→                            <p className="cv-header-label">Post</p>
369→                        </motion.div>
370→                    )}
371→                </AnimatePresence>
372→
373→                <article className="cv-article">
374→                    {postData?.isRepost ? (
375→                        <>
376→                            {/* ── Repost view: quote on top, original post nested below ── */}
377→
378→                            {/* Reposter quote section */}
379→                            <div className="cv-repost-quote-section">
380→                                <div className="cv-repost-badge">
381→                                    <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="var(--text-faint)">
382→                                        <path d="M7 7h10l-1.293-1.293a1 1 0 0 1 1.414-1.414l3 3a1 1 0 0 1 0 1.414l-3 3a1 1 0 0 1-1.414-1.414L17 9H7a1 1 0 0 1-1-1V5a1 1 0 0 1 2 0v2zm10 10H7l1.293 1.293a1 1 0 0 1-1.414 1.414l-3-3a1 1 0 0 1 0-1.414l3-3a1 1 0 1 1 1.414 1.414L7 15h10a1 1 0 0 1 1 1v3a1 1 0 0 1-2 0v-2z"/>
383→                                    </svg>
384→                                    <span
385→                                        onClick={(e) => handleclickUserProfile(e, user?.userData?.[0]?.id, postData?.userId)}
386→                                        className="cv-repost-badge-name"
387→                                    >
388→                                        {postData?.name}
389→                                    </span>
390→                                    <VerifiedBadge badge={postData?.badge} size={14} />
391→                                    <span className="cv-repost-badge-label">reposted</span>
392→                                    <span className="cv-repost-badge-date">
393→                                        {new Date(postData?.created_at).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}
394→                                    </span>
395→                                </div>
396→
397→                                {postData.repostCaption && (
398→                                    <p className="cv-repost-caption">{postData.repostCaption}</p>
399→                                )}
400→                            </div>
401→
402→                            {/* Original post nested below */}
403→                            {postData.repostSource ? (
404→                                <div
405→                                    className="cv-repost-embedded"
406→                                    onClick={(e) => {
407→                                        e.stopPropagation();
408→                                        const src = postData.repostSource;
409→                                        const srcParsed = ParseContent(src.content);
410→                                        viewContent(
411→                                            e,
412→                                            src.content,
413→                                            srcParsed?.wholeText || '',
414→                                            src.title,
415→                                            src.users?.id,
416→                                            src.users?.name,
417→                                            src.users?.image_url,
418→                                            src.created_at,
419→                                            src.id,
420→                                            false, 0, false, 0, 0,
421→                                            src.users?.badge,
422→                                            src.post_type,
423→                                            src.canvas_doc
424→                                        );
425→                                    }}
426→                                >
427→                                    <div className="cv-repost-embedded-meta">
428→                                        <img className="cv-repost-embedded-avatar" src={postData.repostSource.users?.image_url || '/assets/profile.jpg'} alt="original author" />
429→                                        <span className="cv-repost-embedded-name">{postData.repostSource.users?.name}</span>
430→                                        <VerifiedBadge badge={postData.repostSource.users?.badge} size={14} />
431→                                        <span className="cv-repost-embedded-date">
432→                                            {new Date(postData.repostSource.created_at).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })}
433→                                        </span>
434→                                    </div>
435→                                    <h2 className="cv-repost-embedded-title">{postData.repostSource.title}</h2>
436→                                    <div className="cv-repost-embedded-content">
437→                                        {postData.repostSource.post_type === 'canvas' ? (
438→                                            <CanvasViewer canvasDoc={parseCanvasDoc(postData.repostSource.canvas_doc)} />
439→                                        ) : postData.repostSource.content ? (
440→                                            <LexicalComposer initialConfig={{
441→                                                namespace: "RepostSourceViewer",
442→                                                theme: theme,
443→                                                editable: false,
444→                                                editorState: postData.repostSource.content,
445→                                                nodes: [HeadingNode, ImageNode, QuoteNode],
446→                                                onError(error) { throw error; },
447→                                            }}>
448→                                                <RichTextPlugin
449→                                                    contentEditable={<ContentEditable />}
450→                                                    ErrorBoundary={LexicalErrorBoundary}
451→                                                />
452→                                            </LexicalComposer>
453→                                        ) : null}
454→                                    </div>
455→                                </div>
456→                            ) : (
457→                                <div className="cv-repost-unavailable">
458→                                    This post is no longer available
459→                                </div>
460→                            )}
461→
462→                            {/* Action bar */}
463→                            <div className="cv-actions">
464→                                <button
465→                                    className="cv-action-btn"
466→                                    onClick={(e) => handleClickLike(e, postData?.journalId, postData?.userId, user?.userData?.[0].image_url, user?.userData?.[0].name, user?.userData?.[0].user_email)}
